import socket
import pygame
import sys
import threading
from collections import defaultdict

class GameServer:
    def __init__(self, host='127.0.0.1', port=5555):
        self.host = host
        self.port = port
        self.server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.players = defaultdict(lambda: (0, 0))

    def start(self):
        self.server.bind((self.host, self.port))
        self.server.listen()
        print('Server started at {}:{}'.format(self.host, self.port))

        while True:
            client_socket, addr = self.server.accept()
            print("Client connected:", addr)
            thread = threading.Thread(target=handle_client, args=(client_socket, self.players))
            thread.start()

def handle_client(client_socket, players):
    while True:
        player_data = client_socket.recv(1024)
        if not player_data:
            break
        process_player_data(player_data, players)

def process_player_data(data, players):
    x, y = data.split(',')[0], data.split(',')[1]
    players[(x, y)] += 1
    broadcast(players)

def broadcast(players):
    for client in clients:
        client_socket = clients[client]
        player_data = serialize_positions(players)
        client_socket.sendall(player_data)

def serialize_positions(players):
    pos_str = ''
    for position, count in players.items():
        pos_str += str(position[0]) + ',' + str(position[1]) + ',' + str(count) + '\n'
    return pos_str

